<!DOCTYPE html>
<html lang="zh-TW">
<head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>ERA 行動模塊 - 維奧萊塔定製版</title>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <style>
        :root {
            /* ── Dark Love Theme ── */
            --panel-bg:          linear-gradient(145deg, #1a0810, #220c16);
            --border-color:      #6d1a2a;
            --border-inner:      rgba(255, 80, 120, 0.15);

            /* Header decoration */
            --line-gradient:     linear-gradient(to right, transparent, #c23456, transparent);

            /* Buttons */
            --btn-bg:            rgba(255, 255, 255, 0.04);
            --btn-border:        rgba(110, 26, 42, 0.8);
            --btn-hover-bg:      rgba(180, 30, 60, 0.22);
            --btn-hover-border:  #a0243c;
            --btn-active-bg:     rgba(180, 30, 60, 0.12);

            /* Text */
            --text-main:         #f0c0cc;
            --text-name:         #ff8aaa;
            --text-title:        #e05070;
            --text-label:        #ff7a96;

            /* Typography */
            --font-base:         clamp(0.8rem, 2.5vw, 0.95rem);
            --font-stack:        -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
        }

        /* 動畫效果定義 */
        @keyframes slideUpFade {
            from { opacity: 0; transform: translateY(10px); }
            to   { opacity: 1; transform: translateY(0); }
        }

        @keyframes pulse-glow {
            0%   { box-shadow: 0 10px 25px rgba(0, 0, 0, 0.5), inset 0 1px 0 rgba(255, 100, 120, 0.1); }
            50%  { box-shadow: 0 15px 30px rgba(180, 30, 60, 0.4), inset 0 1px 0 rgba(255, 100, 120, 0.15); }
            100% { box-shadow: 0 10px 25px rgba(0, 0, 0, 0.5), inset 0 1px 0 rgba(255, 100, 120, 0.1); }
        }

        /* 基礎樣式 */
        body {
            font-family: var(--font-stack);
            margin: 0;
            padding: 6px;
            background-color: transparent;
            min-height: 20vh;
            overflow: auto;
            display: flex;
            justify-content: center;
            align-items: center;
            box-sizing: border-box;
            font-size: var(--font-base);
            color: var(--text-main);
        }

        /* ── Main container ── */
        .era-actions-container {
            width: 100%;
            box-sizing: border-box;
            margin: 14px 9px;
            padding: clamp(12px, 3.5vw, 20px) clamp(12px, 4vw, 22px);
            background: var(--panel-bg);
            border-radius: 16px;
            border: 1px solid var(--border-color);
            animation: slideUpFade 0.6s cubic-bezier(0.2, 0.8, 0.2, 1) both,
                       pulse-glow 3s infinite ease-in-out;
        }

        /* ── Header ── */
        .era-actions-header {
            display: flex;
            justify-content: center;
            align-items: center;
            margin-bottom: 20px;
            position: relative;
        }

        /* 裝飾性線條 */
        .header-line {
            height: 2px;
            background: var(--line-gradient);
            width: 100%;
            position: absolute;
            bottom: -8px;
            opacity: 0.5;
        }

        /* 標題樣式 */
        .era-actions-title {
            text-align: center;
            font-weight: bold;
            color: var(--text-name);
            margin: 0;
            font-size: clamp(0.95rem, 4vw, 1.1rem);
            text-shadow: 0 0 12px rgba(255, 100, 140, 0.5);
            letter-spacing: 2px;
        }

        .era-actions-title i {
            font-size: 0.8em;
            color: var(--text-title);
            opacity: 0.9;
        }

        /* ── 2×2 button grid ── */
        .era-action-buttons {
            display: grid;
            grid-template-columns: repeat(2, 1fr);
            gap: clamp(8px, 3vw, 14px);
        }

        /* 按鈕樣式 */
        .era-action-btn {
            position: relative;
            padding: clamp(10px, 3.5vw, 14px) 8px;
            font-size: clamp(0.72rem, 3vw, 0.85rem);
            font-weight: 600;
            color: var(--text-label);
            background: var(--btn-bg);
            border: 1px solid var(--btn-border);
            border-radius: 10px;
            cursor: pointer;
            transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
            text-align: center;
            overflow-wrap: break-word;
            word-break: break-word;
            min-height: 44px;
            display: flex;
            justify-content: center;
            align-items: center;
            font-family: var(--font-stack);
            box-shadow: 0 2px 5px rgba(0, 0, 0, 0.3);
        }

        /* 按鈕交互效果 */
        .era-action-btn:hover {
            background: var(--btn-hover-bg);
            border-color: var(--btn-hover-border);
            color: #ffd0dc;
            transform: translateY(-3px) scale(1.03);
            box-shadow: 0 6px 16px rgba(180, 30, 60, 0.3);
        }

        .era-action-btn:active {
            transform: translateY(-1px) scale(0.98);
            background: var(--btn-active-bg);
            box-shadow: 0 2px 8px rgba(180, 30, 60, 0.15);
        }

        /* 按鈕內的圖標間距 */
        .era-action-btn i {
            margin-right: 6px;
            font-size: 0.9em;
            opacity: 0.8;
        }
    </style>
</head>
<body>

    <div class="era-actions-container">
        <div class="era-actions-header">
            <h4 class="era-actions-title">
                <i class="fa-solid fa-star-of-david"></i>
                行動選項
                <i class="fa-solid fa-star-of-david"></i>
            </h4>
            <div class="header-line"></div>
        </div>

        <div class="era-action-buttons">
            <button class="era-action-btn">$1</button>
            <button class="era-action-btn">$2</button>
            <button class="era-action-btn">$3</button>
            <button class="era-action-btn">$4</button>
        </div>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', () => {
            /**
             * Sends text into the SillyTavern input textarea.
             * @param {string} text - The text to send.
             */
            const handleSend = (text) => {
                try {
                    const inputArea = window.parent.document.querySelector('#send_textarea');
                    if (!inputArea) {
                        throw new Error('SillyTavern UI not found.');
                    }
                    inputArea.value = inputArea.value.trim().length > 0
                        ? inputArea.value + '\n' + text
                        : text;
                    inputArea.dispatchEvent(new Event('input', { bubbles: true }));

                    // 可選：自動點擊發送按鈕（取消註解以啟用）
                    // const sendBtn = window.parent.document.querySelector('#send_butt');
                    // if (sendBtn) sendBtn.click();
                } catch (error) {
                    console.warn('SillyTavern UI 連結失敗:', error);
                    alert(`自動操作失敗，請手動複製:\n\n${text}`);
                }
            };

            // 綁定按鈕事件
            document.querySelectorAll('.era-action-btn').forEach(btn => {
                btn.addEventListener('click', function() {
                    const text = this.innerText.trim();
                    if (text) {
                        handleSend(text);
                        // 點擊回饋動畫
                        this.style.transform = 'scale(0.95)';
                        setTimeout(() => this.style.transform = '', 150);
                    }
                });
            });
        });
    </script>
</body>
</html>
